"""
title: WidgeTDC Cognitive Orchestrator
author: WidgeTDC Platform Agent
version: 1.0.0
description: Giver adgang til dyb RLM-reasoning og multi-agent debate chains via WidgeTDC Orchestrator v2.0.0.
"""

import requests
import json
from datetime import datetime, timezone


class Tools:
    def __init__(self):
        self.base_url = "https://orchestrator-production-c27e.up.railway.app"
        self.headers = {
            "Authorization": "Bearer WidgeTDC_Orch_2026",
            "Content-Type": "application/json",
        }

    def _format_response(self, title: str, content: str, endpoint: str) -> str:
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        return (
            f"### 🧠 {title}\n\n"
            f"{content}\n\n"
            f"---\n"
            f"**Kilde:** `WidgeTDC Orchestrator v2.0.0` | **Endpoint:** `{endpoint}` | **Timestamp:** `{timestamp}`"
        )

    def _handle_error(self, error_msg: str, endpoint: str) -> str:
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        return (
            f"### ⚠️ WidgeTDC Orchestrator Fejl\n\n"
            f"> **System Alert:** Kunne ikke fuldføre den kognitive handling.\n"
            f"> **Detaljer:** {error_msg}\n\n"
            f"---\n"
            f"**Kilde:** `WidgeTDC Orchestrator v2.0.0` | **Endpoint:** `{endpoint}` | **Timestamp:** `{timestamp}`"
        )

    def trigger_architecture_debate(self, topic: str) -> str:
        endpoint = "/api/tools/run_chain"
        url = f"{self.base_url}{endpoint}"

        payload = {
            "name": f"Architecture Debate: {topic}",
            "mode": "debate",
            "steps": [
                {
                    "agent_id": "architect_alpha",
                    "cognitive_action": "analyze",
                    "prompt": f"Fordele FOR: {topic}",
                },
                {
                    "agent_id": "architect_beta",
                    "cognitive_action": "analyze",
                    "prompt": f"Risici IMOD: {topic}",
                },
                {
                    "agent_id": "lead_arbitrator",
                    "cognitive_action": "plan",
                    "prompt": f"Syntetisér og træf beslutning om: {topic}",
                },
            ],
        }

        try:
            response = requests.post(
                url, headers=self.headers, json=payload, timeout=60
            )
            response.raise_for_status()
            data = response.json()
            result_text = data.get("result", {}).get(
                "final_output", json.dumps(data, indent=2)
            )
            return self._format_response(
                f"Architecture Arbitration: {topic}", result_text, endpoint
            )
        except requests.exceptions.RequestException as e:
            return self._handle_error(str(e), endpoint)

    def reason_deeply(self, question: str, mode: str = "reason") -> str:
        endpoint = "/api/tools/reason_deeply"
        url = f"{self.base_url}{endpoint}"
        payload = {"question": question, "mode": mode}

        try:
            response = requests.post(
                url, headers=self.headers, json=payload, timeout=45
            )
            response.raise_for_status()
            data = response.json()
            result_text = data.get("result", json.dumps(data, indent=2))
            return self._format_response(
                f"RLM Deep Analysis ({mode.upper()})", result_text, endpoint
            )
        except requests.exceptions.RequestException as e:
            return self._handle_error(str(e), endpoint)
